function moveActor(actor: Actor): Result<boolean, MoveError> {
  if (actor.moveDir === MoveDir.NoDir) {
    return Ok(false);
  }
  if (actor.moveDir >= 8) {
    return Err(new InvalidMoveDirError(actor.moveDir));
  }
  const tryX = actor.x + actor.info.speed * xspeed[actor.moveDir];
  const tryY = actor.y + actor.info.speed * yspeed[actor.moveDir];
  const moveResult = tryMove(actor, tryX, tryY);
  if (moveResult.isErr()) {
    return moveResult;
  }
  actor.z = actor.floorZ;
  return Ok(true);
}
